1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	const ALIKE_BLOCK_SIZE = 3;
10	const ALIKE_BLOCK_PREMIUM = 60;
11	
12	const BASE_PREMIUM: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number };
22	type Step = { items: Item[] };
23	type Customer = { yearsWithMHPCO: number };
24	type Scenario = { customer: Customer; steps: Step[] };
25	
26	const basePremiumOf = (item: Item): number => BASE_PREMIUM[item.type];
27	
28	const groupByType = (items: Item[]): Item[][] => {
29	  const groups = Map.groupBy(items, (item) => item.type);
30	  return Array.from(groups.values());
31	};
32	
33	const sumBasePremiums = (items: Item[]): number =>
34	  items.reduce((acc, item) => acc + basePremiumOf(item), 0);
35	
36	const basePremiumForGroup = (group: Item[]): number =>
37	  group.length === ALIKE_BLOCK_SIZE ? ALIKE_BLOCK_PREMIUM : sumBasePremiums(group);
38	
39	const basePremiumForItems = (items: Item[]): number =>
40	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
41	
42	const cursedSurcharge = (item: Item): number =>
43	  item.cursed ? basePremiumOf(item) * CURSED_SURCHARGE_RATE : 0;
44	
45	const highEnchantmentSurcharge = (item: Item): number =>
46	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
47	    ? basePremiumOf(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
48	    : 0;
49	
50	const itemSurcharges = (items: Item[]): number =>
51	  items.reduce(
52	    (sum, item) => sum + cursedSurcharge(item) + highEnchantmentSurcharge(item),
53	    0,
54	  );
55	
56	const firstInsuranceSurcharge = (basePremium: number): number =>
57	  basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
58	
59	const loyaltyDiscount = (basePremium: number, customer: Customer): number =>
60	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
61	
62	const followUpDiscount = (basePremium: number, isFollowUp: boolean): number =>
63	  isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
64	
65	const quotePremium = (items: Item[], customer: Customer, isFollowUp: boolean): number => {
66	  const basePremium = basePremiumForItems(items);
67	  return (
68	    Math.ceil(
69	      basePremium +
70	        itemSurcharges(items) +
71	        firstInsuranceSurcharge(basePremium) -
72	        loyaltyDiscount(basePremium, customer) -
73	        followUpDiscount(basePremium, isFollowUp),
74	    ) + PROCESSING_FEE
75	  );
76	};
77	
78	export const runScenario = (scenario: Scenario): unknown => {
79	  const results = scenario.steps.map((step, index) => ({
80	    premium: quotePremium(step.items, scenario.customer, index > 0),
81	  }));
82	  return { results };
83	};
